async function reseed() {
  console.log("Truncating teachings table…");
  await sql`TRUNCATE TABLE teachings RESTART IDENTITY`;

  console.log(`Inserting ${teachings.length} teachings…`);
  const BATCH = 50;
  for (let i = 0; i < teachings.length; i += BATCH) {
    const batch = teachings.slice(i, i + BATCH);
    const values = batch
      .map((_, j) => `($${j * 6 + 1}, $${j * 6 + 2}, $${j * 6 + 3}, $${j * 6 + 4}, $${j * 6 + 5}, $${j * 6 + 6})`)
      .join(", ");
    const params = batch.flatMap((r) => [r.sn, r.title.trim(), r.series.trim(), r.date, r.audioUrl, ""]);
    await sql.query(
      `INSERT INTO teachings (sn, title, series, date, audio_url, file_key) VALUES ${values}`,
      params,
    );
    console.log(`  Inserted rows ${i + 1}–${Math.min(i + BATCH, teachings.length)}`);
  }

  const count = await sql`SELECT COUNT(*) FROM teachings`;
  console.log(`Done. Total teachings in DB: ${count[0].count}`);
}

reseed().catch((err) => {
  console.error(err);
  process.exit(1);
});
